// Obtener el contexto completo del router
const ctx = $input.first().json;

// Calcular fechas disponibles: próximos 5 días laborales
const diasLaborales = ctx.dias_laborales || ['lunes','martes','miercoles','jueves','viernes'];
const duracion = ctx.duracion_cita_min || 30;
const horaInicio = ctx.horario_inicio || '09:00';
const horaFin = ctx.horario_fin || '18:00';

const diasMap = {
  'domingo': 0, 'lunes': 1, 'martes': 2, 'miercoles': 3,
  'jueves': 4, 'viernes': 5, 'sabado': 6
};
const diasNumericos = diasLaborales.map(d => diasMap[d.toLowerCase()] ?? 1);

// Generar los próximos 5 días laborales
const hoy = new Date();
const diasDisp = [];
let diasBuscados = 0;
let i = 1;
while (diasDisp.length < 3 && i <= 14) {
  const fecha = new Date(hoy);
  fecha.setDate(hoy.getDate() + i);
  if (diasNumericos.includes(fecha.getDay())) {
    diasDisp.push(fecha.toISOString().split('T')[0]);
  }
  i++;
}

return [{
  json: {
    ...ctx,
    dias_disponibles: diasDisp,
    horario_inicio_calc: horaInicio,
    horario_fin_calc: horaFin,
    duracion_calc: duracion
  }
}];

// Construir slots libres por día
const ctx = $('Preparar Slots Disponibles').item.json;
const citasOcupadas = $input.all().map(i => i.json);

const duracion = ctx.duracion_calc || 30;
const [hIni, mIni] = (ctx.horario_inicio_calc || '09:00').split(':').map(Number);
const [hFin, mFin] = (ctx.horario_fin_calc || '18:00').split(':').map(Number);

const slotsLibres = [];

for (const dia of (ctx.dias_disponibles || [])) {
  const citasDelDia = citasOcupadas.filter(c => c.fecha === dia);

  let slotStart = hIni * 60 + mIni;
  const slotEnd = hFin * 60 + mFin;

  const slots = [];
  while (slotStart + duracion <= slotEnd && slots.length < 3) {
    const slotIso = `${dia}T${String(Math.floor(slotStart/60)).padStart(2,'0')}:${String(slotStart%60).padStart(2,'0')}:00`;
    const slotEndTime = slotStart + duracion;

    const ocupado = citasDelDia.some(c => {
      const cIni = c.hora_inicio ? parseInt(c.hora_inicio.replace(':','')) : 0;
      const cFin = c.hora_fin ? parseInt(c.hora_fin.replace(':','')) : 0;
      const sIni = slotStart;
      const sFin = slotEndTime;
      return !(sFin <= cIni || sIni >= cFin);
    });

    if (!ocupado) {
      const hora = `${String(Math.floor(slotStart/60)).padStart(2,'0')}:${String(slotStart%60).padStart(2,'0')}`;
      slots.push(hora);
    }
    slotStart += duracion;
  }

  if (slots.length > 0) {
    // Formatear fecha legible en español
    const fechaObj = new Date(dia + 'T12:00:00');
    const opciones = { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'UTC' };
    const fechaLegible = fechaObj.toLocaleDateString('es-ES', opciones);
    slotsLibres.push({ fecha: dia, fecha_legible: fechaLegible, slots });
  }
}

let mensaje = `📅 *Disponibilidad para tu cita con ${ctx.nombre_despacho || ctx.abogado_nombre}*\n\n`;
if (slotsLibres.length === 0) {
  mensaje += '⚠️ Por el momento no tenemos horarios disponibles en los próximos días. Te contactaremos para coordinar.';
} else {
  mensaje += 'Estos son nuestros próximos horarios disponibles:\n\n';
  for (const dia of slotsLibres) {
    mensaje += `📆 *${dia.fecha_legible}*\n`;
    dia.slots.forEach(s => { mensaje += `   • ${s} hrs\n`; });
    mensaje += '\n';
  }
  mensaje += '¿Cuál horario te viene mejor? Responde con la fecha y hora (ej: *Martes a las 10:00*).';
}

return [{
  json: {
    ...ctx,
    slots_libres: slotsLibres,
    hay_slots: slotsLibres.length > 0,
    mensaje_disponibilidad: mensaje
  }
}];

// Intentar parsear la fecha/hora del mensaje del lead
const ctx = $('Construir Mensaje Disponibilidad').item.json;
const mensaje = ctx.message_text || '';

// Patrones simples para detectar confirmación de horario
const regexHora = /(\d{1,2})[:\.]?(\d{0,2})\s*(?:hrs?|horas?|am|pm)?/i;
const regexFecha = /(lunes|martes|mi[eé]rcoles|jueves|viernes|s[aá]bado|domingo|hoy|ma[nñ]ana|\d{1,2}[\/\-]\d{1,2})/i;

const matchHora = mensaje.match(regexHora);
const matchFecha = mensaje.match(regexFecha);

let fechaSeleccionada = null;
let horaSeleccionada = null;

if (matchHora) {
  const h = matchHora[1].padStart(2,'0');
  const m = (matchHora[2] || '00').padStart(2,'0');
  horaSeleccionada = `${h}:${m}`;
}

// Buscar en los slots disponibles
if (horaSeleccionada && ctx.slots_libres?.length > 0) {
  for (const diaSlot of ctx.slots_libres) {
    if (diaSlot.slots.some(s => s.startsWith(horaSeleccionada.substring(0,2)))) {
      fechaSeleccionada = diaSlot.fecha;
      break;
    }
  }
  if (!fechaSeleccionada && ctx.slots_libres.length > 0) {
    fechaSeleccionada = ctx.slots_libres[0].fecha;
  }
}

const puedeCitar = !!(fechaSeleccionada && horaSeleccionada);

return [{
  json: {
    ...ctx,
    fecha_cita: fechaSeleccionada,
    hora_cita: horaSeleccionada,
    puede_citar: puedeCitar,
    datetime_cita: puedeCitar ? `${fechaSeleccionada}T${horaSeleccionada}:00` : null
  }
}];

